import{_ as e,c as a,o as s,a as n}from"./app.1cfac776.js";const h=JSON.parse('{"title":"Introducci\xF3n","description":"","frontmatter":{},"headers":[],"relativePath":"ense\xF1anza/intro.md"}'),o={name:"ense\xF1anza/intro.md"},t=n('<h1 id="introduccion" tabindex="-1">Introducci\xF3n <a class="header-anchor" href="#introduccion" aria-hidden="true">#</a></h1><p><strong>IesApp y la labor docente</strong></p><p>Este bloque de funcionalidades es el que mejor est\xE1 gestionado en SIGAD. Buena parte de informaci\xF3n que aqu\xED encontramos est\xE1 en SIGAD pero hay algunas cuestiones que hacen interesante tenerlas presentes en IesApp:</p><ul><li>Se trata de datos necesarios para <strong>funcionalidades m\xE1s avanzadas</strong>. Esas que no est\xE1n en SIGAD.</li><li>La <strong>disponibilidad y facilidad de uso</strong> hace que profesores y jefes de estudio busquen antes en IesApp que en SIGAD.</li><li>Los <strong>conserjes</strong> necesitan informaci\xF3n de horarios, alumnos, grupos, ... Antes de IesApp esto se lograba haciendo copias en papel del DOC. Esta era una mala decisi\xF3n. Las copias llegaban tarde y siempre quedaban obsoletas. Sabido es que los cambios son cotidianas en todos los centros.</li></ul><p>Vamos a ver con m\xE1s detalle qu\xE9 posibilidades nos brinda la aplicaci\xF3n.</p>',5),i=[t];function r(d,c,l,p,u,_){return s(),a("div",null,i)}const f=e(o,[["render",r]]);export{h as __pageData,f as default};
